interface Offer {
  title: string;
  description: string;
}

interface IndustryCTAProps {
  eyebrow?: string;
  headline: string;
  description?: string;
  primaryCtaText?: string;
  primaryCtaHref?: string;
  secondaryCtaText?: string;
  secondaryCtaHref?: string;
  backgroundImage: string;
  backgroundImageAlt?: string;
  offers?: Offer[];
}

export function IndustryCTA({
  eyebrow = "Get Started",
  headline,
  description,
  primaryCtaText = "Book a call",
  primaryCtaHref = "/contact",
  secondaryCtaText,
  secondaryCtaHref,
  backgroundImage,
  backgroundImageAlt = "Background",
  offers,
}: IndustryCTAProps) {
  const sectionRef = useRef<HTMLElement>(null);
  const isInView = useInView(sectionRef, { once: true, amount: 0.3 });

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.15,
        delayChildren: 0.1,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.6,
        ease: [0.25, 0.46, 0.45, 0.94] as [number, number, number, number],
      },
    },
  };

  return (
    <motion.section
      ref={sectionRef}
      className="flex flex-col gap-[20px] items-start justify-center px-[120px] py-[80px] w-full"
      variants={containerVariants}
      initial="hidden"
      animate={isInView ? "visible" : "hidden"}
    >
      {/* Main CTA with Background Image */}
      <motion.div
        className="relative flex flex-col gap-[30px] h-[363px] items-center justify-center overflow-hidden px-[60px] py-[51px] w-full"
        variants={itemVariants}
      >
        {/* Background Image */}
        <div className="absolute inset-0">
          <Image
            src={backgroundImage}
            alt={backgroundImageAlt}
            fill
            sizes="100vw"
            className="object-cover"
          />
        </div>

        {/* Content */}
        <motion.div className="relative flex flex-col gap-[15px] items-center text-center text-[#fdfdfd] z-10" variants={itemVariants}>
          {eyebrow && (
            <motion.span className="font-eyebrow text-[13px] tracking-[-0.52px] uppercase" variants={itemVariants}>
              {eyebrow}
            </motion.span>
          )}
          <motion.h2 className="font-heading text-[48px] font-semibold tracking-[-1.92px] leading-tight max-w-[611px]" variants={itemVariants}>
            {headline}
          </motion.h2>
          {description && (
            <motion.p className="font-body text-[20px] tracking-[-0.8px] max-w-[634px]" variants={itemVariants}>
              {description}
            </motion.p>
          )}
        </motion.div>

        {/* CTA Buttons */}
        <motion.div className="relative flex gap-[30px] items-center z-10" variants={itemVariants}>
          <BookCallButton
            text={primaryCtaText}
            href={primaryCtaHref}
            variant="inverted"
          />
          {secondaryCtaText && secondaryCtaHref && (
            <BookCallButton
              text={secondaryCtaText}
              href={secondaryCtaHref}
              variant="outline"
            />
          )}
        </motion.div>
      </motion.div>

      {/* Offer Cards */}
      {offers && offers.length > 0 && (
        <motion.div className="flex gap-[20px] items-start w-full" variants={containerVariants}>
          {offers.map((offer, index) => (
            <motion.div
              key={index}
              className="flex flex-col flex-1 gap-[30px] items-start p-[30px] bg-[#f8f8f8] border border-[#e6e6e6] overflow-hidden"
              variants={itemVariants}
            >
              {/* Icon */}
              <div className="flex items-center justify-center size-[40px] bg-[#eaeaea] border border-[#dfdfdf]">
                <StarIcon className="size-[21px] text-[#9a9a9a]" />
              </div>

              {/* Content */}
              <div className="flex flex-col gap-[6px] items-start w-full">
                <h3 className="font-heading text-[24px] font-semibold text-black tracking-[-0.96px]">
                  {offer.title}
                </h3>
                <p className="font-body text-[14px] font-bold text-[#a2a2a2] tracking-[-0.56px] overflow-hidden text-ellipsis">
                  {offer.description}
                </p>
              </div>
            </motion.div>
          ))}
        </motion.div>
      )}
    </motion.section>
  );
}
